package controller;
import dao.AdminLoyaltyDAO;import dto.User;import java.io.IOException;import java.math.BigDecimal;import javax.servlet.ServletException;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import mylib.AppKeys;
@WebServlet(name="AdminLoyaltyServlet",urlPatterns={"/admin/tiers","/admin/tiers/save","/admin/rewards","/admin/rewards/save","/admin/loyalty-settings","/admin/loyalty-settings/save"})
public class AdminLoyaltyServlet extends HttpServlet{
 private User admin(HttpServletRequest q,HttpServletResponse p)throws IOException{HttpSession s=q.getSession(false);User u=s==null?null:(User)s.getAttribute(AppKeys.SESSION_ACCOUNT);if(u==null){p.sendError(401);return null;}if(!"ADMIN".equals(u.getRoleName())){p.sendError(403);return null;}return u;}
 protected void doGet(HttpServletRequest q,HttpServletResponse p)throws IOException,ServletException{if(admin(q,p)==null)return;try{AdminLoyaltyDAO d=new AdminLoyaltyDAO();String path=q.getServletPath();if(path.endsWith("tiers")){q.setAttribute("tiers",d.tiers());q.getRequestDispatcher("/admin/pages/tier-management.jsp").forward(q,p);}else if(path.endsWith("rewards")){q.setAttribute("rewards",d.rewards());q.getRequestDispatcher("/admin/pages/reward-management.jsp").forward(q,p);}else{q.setAttribute("configs",d.configs());q.getRequestDispatcher("/admin/pages/loyalty-settings.jsp").forward(q,p);}}catch(Exception e){log("Admin loyalty load failed",e);throw new ServletException(e);}}
 protected void doPost(HttpServletRequest q,HttpServletResponse p)throws IOException{User u=admin(q,p);if(u==null)return;String base;try{AdminLoyaltyDAO d=new AdminLoyaltyDAO();String path=q.getServletPath();if(path.contains("loyalty-settings")){d.saveConfigs(u.getId(),q.getParameter("pointExpiryMonths"),q.getParameter("pointRateAmount"),q.getParameter("defaultVoucherValidDays"));base="/admin/loyalty-settings";}else if(path.contains("rewards")){String raw=q.getParameter("rewardId");Integer id=raw==null||raw.trim().isEmpty()?null:Integer.valueOf(raw);String sid=q.getParameter("targetServiceId");Integer service=sid==null||sid.trim().isEmpty()?null:Integer.valueOf(sid);String mx=q.getParameter("maximumDiscount");d.saveReward(id,q.getParameter("rewardName"),Integer.parseInt(q.getParameter("requiredPoints")),q.getParameter("rewardType"),new BigDecimal(q.getParameter("rewardValue")),service,Integer.parseInt(q.getParameter("validDays")),mx==null||mx.isEmpty()?null:new BigDecimal(mx),Boolean.parseBoolean(q.getParameter("isActive")));base="/admin/rewards";}else{d.saveTier(Integer.parseInt(q.getParameter("tierId")),q.getParameter("tierName"),Integer.parseInt(q.getParameter("minPoints")),new BigDecimal(q.getParameter("discountPercent")),Integer.parseInt(q.getParameter("priorityScore")),q.getParameter("benefits"),Boolean.parseBoolean(q.getParameter("isActive")));base="/admin/tiers";}q.getSession().setAttribute("flashSuccess","Lưu cấu hình thành công.");}catch(Exception e){log("Admin loyalty save rejected",e);q.getSession().setAttribute("flashError","Dữ liệu không hợp lệ hoặc bị trùng.");String path=q.getServletPath();base=path.contains("rewards")?"/admin/rewards":path.contains("tiers")?"/admin/tiers":"/admin/loyalty-settings";}p.sendRedirect(q.getContextPath()+base);}
}
